const { text, session, userId, phone } = $input.first().json;
const step = session.checkoutStep;
const collected = { ...session.collectedData };
if (step === 'NAME') collected.name = text;
if (step === 'DOB') collected.dob = text;
if (step === 'BIRTH_TIME') collected.birthTime = text;
if (step === 'BIRTH_PLACE') collected.birthPlace = text;
const steps = ['NAME', 'DOB', 'BIRTH_TIME', 'BIRTH_PLACE', 'DONE'];
const isComplete = steps.indexOf(step) + 1 === steps.length;
const nextStep = steps[steps.indexOf(step) + 1];
const replyText = isComplete ? `Thank you! Generating payment link...` : `Got it. Please provide: ${nextStep}`;
return [{ json: { userId, phone, text, replyText, checkoutComplete: isComplete, session: { ...session, collectedData: collected, checkoutStep: isComplete ? 'DONE' : nextStep, state: isComplete ? 'PAYMENT_SENT' : 'CHECKOUT' } } }];

const data = $('Checkout FSM').first().json;
const rp = $input.first().json;
const paymentUrl = rp.short_url || rp.id;
return [{ json: { ...data, replyText: `Payment Link Ready! \n${paymentUrl}`, session: { ...data.session, state: 'PAYMENT_SENT', paymentUrl } } }];
